composeOverride:
# Generated by McHarbor App Store
services:
  {{serviceName}}:
    image: {{image}}
    container_name: {{containerName}}
    restart: unless-stopped
    stop_grace_period: 30s
    shm_size: {{env.FRIGATE_SHM_SIZE}}
{{ports}}
{{volumes}}
    tmpfs:
      - {{env.FRIGATE_TMPFS}}
    environment:
      FRIGATE_RTSP_PASSWORD: {{env.FRIGATE_RTSP_PASSWORD}}
